using UnityEngine;

public class CameraFollow : MonoBehaviour
{
    public Transform target;           // The object to follow
    public float smoothSpeed = 5f;     // How fast the camera follows
    public Vector3 offset = new Vector3(0, 0, -10);  // Offset from the target

    // Follow settings
    public bool followX = true;
    public bool followY = true;
    public bool clampToBounds = false;
    public Bounds bounds;  // Camera bounds

    void Start()
    {
        // Set camera to orthographic for 2D
        Camera cam = GetComponent<Camera>();
        if (cam != null)
        {
            cam.orthographic = true;
            cam.orthographicSize = 5;
        }

        // If no target is set, try to find the player
        if (target == null)
        {
            GameObject player = GameObject.FindGameObjectWithTag("Player");
            if (player != null)
            {
                target = player.transform;
                Debug.Log("Camera found player: " + target.name);
            }
        }
    }

    void LateUpdate()
    {
        // LateUpdate runs after all Update calls
        // This ensures the camera follows after the player moves

        if (target == null)
        {
            return;
        }

        // Calculate desired position
        Vector3 targetPosition = target.position + offset;

        // Apply follow settings
        if (!followX)
        {
            targetPosition.x = transform.position.x;
        }
        if (!followY)
        {
            targetPosition.y = transform.position.y;
        }

        // Clamp to bounds
        if (clampToBounds)
        {
            targetPosition.x = Mathf.Clamp(targetPosition.x, bounds.min.x, bounds.max.x);
            targetPosition.y = Mathf.Clamp(targetPosition.y, bounds.min.y, bounds.max.y);
        }

        // Smoothly move to target position
        Vector3 smoothedPosition = Vector3.Lerp(transform.position, targetPosition, smoothSpeed * Time.deltaTime);

        // Ensure Z is correct
        smoothedPosition.z = offset.z;

        // Apply position
        transform.position = smoothedPosition;
    }

    // Example: Set new target
    public void SetTarget(Transform newTarget)
    {
        target = newTarget;
        Debug.Log("Camera target set to: " + target.name);
    }

    // Example: Snap to target
    public void SnapToTarget()
    {
        if (target != null)
        {
            transform.position = target.position + offset;
        }
    }

    // Example: Toggle follow
    public void ToggleFollow(bool shouldFollow)
    {
        this.enabled = shouldFollow;
    }
}

